const PLAYER_NAME_COUNTRY_ALIASES = Object.freeze({"Espana":"España","Spain":"España","England":"Inglaterra","Italy":"Italia","Romania":"Rumania","Brazil":"Brasil","Mexico":"México","Peru":"Perú","United States":"Estados Unidos","USA":"Estados Unidos","Japan":"Japón","South Korea":"Corea del Sur","Korea":"Corea del Sur","Morocco":"Marruecos","Germany":"Alemania","France":"Francia"});

function normalizedPlayerNameCountry(value){
  const raw = String(value || 'Argentina').trim();
  if(PLAYER_COUNTRY_NAME_POOLS[raw]) return raw;
  const alias = PLAYER_NAME_COUNTRY_ALIASES[raw];
  if(alias && PLAYER_COUNTRY_NAME_POOLS[alias]) return alias;
  const key = raw.normalize('NFD').replace(/[\u0300-\u036f]/g,'').toLowerCase();
  const found = Object.keys(PLAYER_COUNTRY_NAME_POOLS).find(country => country.normalize('NFD').replace(/[\u0300-\u036f]/g,'').toLowerCase() === key);
  return found || 'Argentina';
}
function playerNamePoolForNationality(nationality){
  return PLAYER_COUNTRY_NAME_POOLS[normalizedPlayerNameCountry(nationality)] || PLAYER_COUNTRY_NAME_POOLS.Argentina;
}
function playerNameUsesSpanishCompatibleScript(value){
  const raw = String(value || '').trim();
  return Boolean(raw) && !/[^\u0000-\u024F\u1E00-\u1EFF\s'’.-]/.test(raw);
}
function playerNameForNationality(id, nationality='Argentina', context='Jugador'){
  const country = normalizedPlayerNameCountry(nationality);
  const pool = playerNamePoolForNationality(country);
  const first = pool.first[hashNumber(`player-name-${country}-${context}-${id}-first`, pool.first.length)];
  const last = pool.last[hashNumber(`player-name-${country}-${context}-${id}-last`, pool.last.length)];
  return `${first} ${last}`;
}
function normalizePlayerNameToSpanishScript(player, context='Jugador'){
  if(!player || typeof player !== 'object' || playerNameUsesSpanishCompatibleScript(player.name)) return false;
  player.name = playerNameForNationality(Number(player.id || player.previousPlayerId || 0), player.nationality || 'Argentina', context);
  return true;
}
function normalizeGamePlayerNamesToSpanishScript(state, seedState=seed){
  if(!state) return 0;
  let changed = 0;
  const seen = new Set();
  const normalizeList = (list, context) => (Array.isArray(list) ? list : []).forEach(player => {
    if(!player || typeof player !== 'object') return;
    const key = `${context}-${Number(player.id || player.previousPlayerId || 0)}-${String(player.name || '')}`;
    if(seen.has(key)) return;
    seen.add(key);
    if(normalizePlayerNameToSpanishScript(player, context)) changed += 1;
  });
  normalizeList(seedState?.players, 'Plantel');
  normalizeList(state.marketPlayers, 'Mercado');
  normalizeList(state.academy?.players, 'Academia');
  normalizeList(state.retiredPlayerPool, 'Retirado');
  const rights = state.managerPlayerPortfolio?.rights;
  if(Array.isArray(rights)){
    rights.forEach(right => {
      if(!right || playerNameUsesSpanishCompatibleScript(right.playerName)) return;
      const active = typeof playerById === 'function' ? playerById(right.playerId) : null;
      right.playerName = active?.name || playerNameForNationality(right.playerId, right.nationality || 'Argentina', 'Cartera');
      changed += 1;
    });
  }
  return changed;
}
